'use client';

import { useEffect } from 'react';
import { Bell, Moon, Shield, ChevronRight, ArrowLeft, Save } from 'lucide-react';
import Link from 'next/link';
import { useThemeStore } from '@/store/themeStore';
import { useAuthStore } from '@/store/authStore';
import { useSettingsStore, type NotificationSettings } from '@/store/settingsStore';
import { toast } from '@/components/ui/Toast';

function Toggle({ enabled, onChange, disabled }: { enabled: boolean; onChange: (v: boolean) => void; disabled?: boolean }) {
  return (
    <button
      onClick={() => !disabled && onChange(!enabled)}
      disabled={disabled}
      className={`relative w-11 h-6 rounded-full transition-colors duration-200 disabled:opacity-40 ${enabled ? 'bg-brand-500' : 'bg-surface-raised border border-surface-border'}`}
    >
      <span className={`absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow transition-transform duration-200 ${enabled ? 'translate-x-5' : 'translate-x-0'}`} />
    </button>
  );
}

export default function SettingsPage() {
  const { isDark, setDark } = useThemeStore();
  const { user } = useAuthStore();
  const { settings, loading, dirty, fetch, update, save } = useSettingsStore();

  // 유저 있으면 설정 로드
  useEffect(() => {
    if (user) fetch(user.id);
  }, [user, fetch]);

  async function handleSave() {
    if (!user) return;
    try {
      await save(user.id);
      toast('success', '설정 저장 완료', '알림 설정이 저장됐어요.');

      // 브라우저 알림 권한 요청 (ON으로 바꾼 항목이 있는 경우)
      const anyOn = Object.values(settings).some(Boolean);
      if (anyOn && typeof window !== 'undefined' && 'Notification' in window) {
        if (Notification.permission === 'default') {
          const perm = await Notification.requestPermission();
          if (perm === 'granted') {
            toast('info', '알림 권한 허용됨', 'KitPick 알림을 받을 수 있어요.');
          }
        }
      }
    } catch {
      toast('error', '저장 실패', '잠시 후 다시 시도해주세요.');
    }
  }

  // 브라우저 푸시 알림 테스트 함수
  function sendTestNotification(label: string) {
    if (typeof window === 'undefined' || !('Notification' in window)) return;
    if (Notification.permission === 'granted') {
      new Notification('KitPick 알림 테스트', {
        body: `${label} 알림이 활성화됐습니다.`,
        icon: '/favicon.ico',
      });
    } else {
      toast('info', '브라우저 알림 권한이 필요해요', '설정 저장 시 권한을 요청합니다.');
    }
  }

  const notifItems: { key: keyof NotificationSettings; label: string; desc: string }[] = [
    { key: 'price_drop_alert', label: '가격 하락 알림',  desc: '찜한 키트 가격이 내려가면 알림' },
    { key: 'reprint_alert',    label: '재판 알림',       desc: '찜한 키트 재판 소식' },
    { key: 'trending_alert',   label: '트렌딩 알림',     desc: '관심 시리즈 트렌딩 진입 시' },
    { key: 'popularity_alert', label: '인기도 변동 알림', desc: '찜한 키트 인기도 급변 시' },
  ];

  return (
    <div className="p-4 sm:p-6 lg:p-10 max-w-2xl mx-auto w-full">
      {/* 헤더 */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <Link href="/profile" className="p-2 rounded-lg text-zinc-500 hover:text-zinc-200 hover:bg-surface-raised transition-colors">
            <ArrowLeft className="w-4 h-4" />
          </Link>
          <h1 className="text-2xl font-bold text-white">설정</h1>
        </div>
        {/* 변경 사항 있을 때만 저장 버튼 표시 */}
        {dirty && user && (
          <button
            onClick={handleSave}
            className="flex items-center gap-2 px-4 py-2 bg-brand-500 hover:bg-brand-400 text-white rounded-lg text-sm font-medium transition-colors"
          >
            <Save className="w-4 h-4" />
            저장
          </button>
        )}
      </div>

      <div className="space-y-4">

        {/* ── 알림 설정 ── */}
        <div className="bg-surface border border-surface-border rounded-xl overflow-hidden">
          <div className="flex items-center justify-between px-4 py-3 border-b border-surface-border">
            <div className="flex items-center gap-2">
              <Bell className="w-4 h-4 text-zinc-400" />
              <h2 className="text-sm font-semibold text-white">알림 설정</h2>
            </div>
            {!user && <span className="text-xs text-zinc-600">로그인 후 설정 가능</span>}
            {loading && <span className="text-xs text-zinc-600">불러오는 중...</span>}
          </div>
          <div className="divide-y divide-surface-border">
            {notifItems.map((item) => (
              <div key={item.key} className="flex items-center justify-between px-4 py-4">
                <div className="flex-1 min-w-0 pr-4">
                  <p className="text-sm text-white">{item.label}</p>
                  <p className="text-xs text-zinc-500 mt-0.5">{item.desc}</p>
                </div>
                <div className="flex items-center gap-3">
                  {/* 토글이 ON 상태이고 저장된 상태면 테스트 버튼 */}
                  {settings[item.key] && !dirty && user && (
                    <button
                      onClick={() => sendTestNotification(item.label)}
                      className="text-[11px] text-zinc-600 hover:text-brand-400 transition-colors"
                    >
                      테스트
                    </button>
                  )}
                  <Toggle
                    enabled={settings[item.key]}
                    onChange={(v) => {
                      if (!user) { toast('info', '로그인이 필요합니다', '알림 설정은 로그인 후 가능해요.'); return; }
                      update(item.key, v);
                      if (v) toast('info', `${item.label} 켜짐`, '저장 버튼을 눌러 적용하세요.');
                    }}
                    disabled={loading}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* ── 앱 설정 ── */}
        <div className="bg-surface border border-surface-border rounded-xl overflow-hidden">
          <div className="flex items-center gap-2 px-4 py-3 border-b border-surface-border">
            <Moon className="w-4 h-4 text-zinc-400" />
            <h2 className="text-sm font-semibold text-white">앱 설정</h2>
          </div>
          <div className="divide-y divide-surface-border">
            <div className="flex items-center justify-between px-4 py-4">
              <div className="flex-1 min-w-0 pr-4">
                <p className="text-sm text-white">다크 모드</p>
                <p className="text-xs text-zinc-500 mt-0.5">{isDark ? '현재: 다크 테마' : '현재: 라이트 테마'}</p>
              </div>
              <Toggle enabled={isDark} onChange={setDark} />
            </div>
          </div>
        </div>

        {/* ── 개인정보 ── */}
        <div className="bg-surface border border-surface-border rounded-xl overflow-hidden">
          <div className="flex items-center gap-2 px-4 py-3 border-b border-surface-border">
            <Shield className="w-4 h-4 text-zinc-400" />
            <h2 className="text-sm font-semibold text-white">개인정보 설정</h2>
          </div>
          <div className="divide-y divide-surface-border">
            <div className="flex items-center justify-between px-4 py-4">
              <div className="flex-1 min-w-0 pr-4">
                <p className="text-sm text-white">AI 모델 학습 허용</p>
                <p className="text-xs text-zinc-500 mt-0.5">내 찜·검색 데이터를 AI 개선에 활용 (익명 처리)</p>
              </div>
              <Toggle enabled={true} onChange={() => {}} />
            </div>
          </div>
        </div>

        {/* ── 앱 정보 ── */}
        <div className="bg-surface border border-surface-border rounded-xl overflow-hidden">
          <div className="px-4 py-3 border-b border-surface-border">
            <h2 className="text-sm font-semibold text-white">앱 정보</h2>
          </div>
          <div className="divide-y divide-surface-border">
            {[
              { label: '버전', value: 'v0.2.0' },
              { label: '서비스 이용약관', value: '' },
              { label: '개인정보 처리방침', value: '' },
              { label: '문의하기', value: 'kitpick@email.com' },
            ].map((item) => (
              <div key={item.label} className="flex items-center justify-between px-4 py-3.5">
                <p className="text-sm text-zinc-300">{item.label}</p>
                <div className="flex items-center gap-1">
                  <p className="text-sm text-zinc-500">{item.value}</p>
                  {!item.value && <ChevronRight className="w-4 h-4 text-zinc-600" />}
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
}
