import { create } from 'zustand';
import { createClient } from '@/lib/supabase/client';

export interface NotificationSettings {
  price_drop_alert: boolean;
  reprint_alert: boolean;
  trending_alert: boolean;
  popularity_alert: boolean;
}

interface SettingsStore {
  settings: NotificationSettings;
  loading: boolean;
  dirty: boolean;
  fetch: (userId: string) => Promise<void>;
  update: (key: keyof NotificationSettings, value: boolean) => void;
  save: (userId: string) => Promise<void>;
  reset: () => void;
}

const defaults: NotificationSettings = {
  price_drop_alert: true,
  reprint_alert:    true,
  trending_alert:   false,
  popularity_alert: false,
};

export const useSettingsStore = create<SettingsStore>((set, get) => ({
  settings: { ...defaults },
  loading: false,
  dirty: false,

  fetch: async (userId) => {
    set({ loading: true });
    const supabase = createClient();
    const { data, error } = await supabase
      .from('user_settings')
      .select('*')
      .eq('user_id', userId)
      .single();

    if (!error && data) {
      set({
        settings: {
          price_drop_alert: data.price_drop_alert,
          reprint_alert:    data.reprint_alert,
          trending_alert:   data.trending_alert,
          popularity_alert: data.popularity_alert,
        },
        loading: false,
        dirty: false,
      });
    } else {
      // 아직 row가 없으면 insert
      await supabase.from('user_settings').insert({ user_id: userId, ...defaults });
      set({ settings: { ...defaults }, loading: false, dirty: false });
    }
  },

  update: (key, value) => {
    set((state) => ({
      settings: { ...state.settings, [key]: value },
      dirty: true,
    }));
  },

  save: async (userId) => {
    const { settings } = get();
    const supabase = createClient();
    await supabase
      .from('user_settings')
      .upsert({ user_id: userId, ...settings, updated_at: new Date().toISOString() });
    set({ dirty: false });
  },

  reset: () => set({ settings: { ...defaults }, dirty: false }),
}));
